class ServerMetrics:
    """Thread-safe server metrics collector."""
    
    def __init__(self):
        import threading
        self._lock = threading.Lock()
        self._requests_processed = 0
        self._total_processing_time_ns = 0
        self._start_time = time.time()
        self._stream_messages_received = 0
        self._stream_messages_sent = 0
        self._errors = 0
    
    def record_request(self, processing_time_ns: int):
        with self._lock:
            self._requests_processed += 1
            self._total_processing_time_ns += processing_time_ns
    
    def record_stream_received(self):
        with self._lock:
            self._stream_messages_received += 1
    
    def record_stream_sent(self):
        with self._lock:
            self._stream_messages_sent += 1
    
    def record_error(self):
        with self._lock:
            self._errors += 1
    
    @property
    def requests_processed(self) -> int:
        with self._lock:
            return self._requests_processed
    
    @property
    def uptime_seconds(self) -> int:
        return int(time.time() - self._start_time)
    
    def get_stats(self) -> dict:
        with self._lock:
            avg_time = (
                self._total_processing_time_ns / self._requests_processed
                if self._requests_processed > 0 else 0
            )
            return {
                'requests_processed': str(self._requests_processed),
                'avg_processing_time_ns': str(int(avg_time)),
                'stream_messages_received': str(self._stream_messages_received),
                'stream_messages_sent': str(self._stream_messages_sent),
                'errors': str(self._errors),
                'uptime_seconds': str(self.uptime_seconds),
            }


